  function showToast(msg, type) {
    const t = document.createElement('div');
    t.textContent = msg;
    t.className = 'app-toast ' + (type === 'error' ? 'error' : 'success');
    t.style.cssText = 'position:fixed; bottom:24px; left:50%; transform:translateX(-50%); z-index:9999; padding:12px 22px; border-radius:10px; font-weight:700; font-size:0.9rem; color:#fff; box-shadow:0 6px 20px rgba(0,0,0,0.25);' + (type === 'error' ? 'background:#c0392b;' : 'background:#0f766e;');
    document.body.appendChild(t);
    setTimeout(() => { t.style.transition = 'opacity 0.4s'; t.style.opacity = '0'; setTimeout(() => t.remove(), 400); }, 2600);
  }

  async function logTransactionToSheet(transaction) {
    const scriptUrl = state.settings.gdrive_script_url;
    if (!scriptUrl) { showToast('⚠ ຍັງບໍ່ໄດ້ຕັ້ງ Apps Script URL — ບໍ່ໄດ້ບັນທຶກຂຶ້ນ Sheet', 'error'); return; }
    try {
      const r = await fetch(scriptUrl, {
        method: 'POST',
        mode: 'cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'log_transaction', transaction: transaction })
      });
      const d = await r.json().catch(() => ({ success: true }));
      if (d && d.success !== false) {
        showToast('✓ ບັນທຶກຂຶ້ນ Google Sheet ສຳເລັດ', 'success');
      } else {
        showToast('⚠ ບັນທຶກຂຶ້ນ Sheet ບໍ່ສຳເລັດ: ' + (d.sheetError || ''), 'error');
      }
    } catch (err) {
      showToast('⚠ ບັນທຶກຂຶ້ນ Sheet ບໍ່ໄດ້ (ກວດອິນເຕີເນັດ)', 'error');
      console.error('logTransactionToSheet failed:', err);
    }
  }

  // ดันยอดขายในเครื่อง (IndexedDB) ขึ้น Sheet ทั้งหมด — สำหรับรายการเก่าที่ค้าง (dedup กันซ้ำ)
  async function pushLocalSalesToSheet() {
    const scriptUrl = state.settings.gdrive_script_url;
    if (!scriptUrl) { alert('ຍັງບໍ່ໄດ້ຕັ້ງຄ່າ Apps Script URL'); return; }
    const all = await window.BokeoDB.getTransactions();
    if (!all.length) { alert('ບໍ່ມີລາຍການຂາຍໃນເຄື່ອງນີ້'); return; }
    if (!confirm('ຈະດັນຍອດຂາຍ ' + all.length + ' ລາຍການຂຶ້ນ Google Sheet (ກັນຊ້ຳອັດຕະໂນມັດ). ດຳເນີນການ?')) return;
    const btn = document.getElementById('btn-push-sales');
    if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> ກຳລັງດັນຂຶ້ນ Sheet...'; }
    let ok = 0, fail = 0;
    for (const tx of all) {
      try {
        const r = await fetch(scriptUrl, {
          method: 'POST', mode: 'cors',
          headers: { 'Content-Type': 'text/plain' },
          body: JSON.stringify({ action: 'log_transaction', transaction: tx })
        });
        const d = await r.json();
        if (d && d.success) ok++; else fail++;
      } catch (e) { fail++; }
    }
    if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-cloud-upload-alt"></i> ດັນຍອດຂາຍຂຶ້ນ Sheet'; }
    alert('ສຳເລັດ: ສົ່ງ ' + ok + ' ລາຍການ | ຜິດພາດ ' + fail + '\n(ລາຍການທີ່ມີໃນ Sheet ແລ້ວ ຖືກກັນຊ້ຳໄວ້)');
  }
  window.pushLocalSalesToSheet = pushLocalSalesToSheet;

  async function uploadPDFToGoogleDrive(blob, fullPath, transaction) {
    const scriptUrl = state.settings.gdrive_script_url;
    if (!scriptUrl) {
      console.log('Google Drive script URL not configured. Skipping upload.');
      return;
    }

    try {
      // Convert Blob to Base64
      const reader = new FileReader();
      const base64Promise = new Promise((resolve) => {
        reader.onloadend = () => {
          const base64data = reader.result.split(',')[1];
          resolve(base64data);
        };
      });
      reader.readAsDataURL(blob);
      const base64Data = await base64Promise;

      const folderId = state.settings.gdrive_folder_id || '1ao3TJesHPrdVCflFPnU6ndcGKAyVPXyC';

      const payload = {
        action: 'upload_invoice',
        file: base64Data,
        filename: fullPath,
        folderId: folderId,
        transaction: transaction
      };

      const response = await fetch(scriptUrl, {
        method: 'POST',
        mode: 'cors',
        headers: {
          'Content-Type': 'text/plain'
        },
        body: JSON.stringify(payload)
      });

      const resData = await response.json();
      if (resData.success) {
        console.log('PDF uploaded and transaction logged successfully via Apps Script. File ID:', resData.fileId);
        if (resData.sheetError) {
          console.error('Google Sheet log error:', resData.sheetError);
          alert('ລະບົບບັນທຶກບິນໄປ Google Drive ສຳເລັດ ແຕ່ບໍ່ສາມາດບັນທຶກລົງ Google Sheet ໄດ້: ' + resData.sheetError);
        }
      } else {
        console.error('Apps Script upload/logging failed:', resData.error);
        throw new Error(resData.error);
      }
    } catch (err) {
      console.error('Failed to upload PDF and log transaction via Apps Script:', err);
      throw err;
    }
  }

